set-variable.value:
@{
    try {
        var body = context.Response.Body.As<Newtonsoft.Json.Linq.JObject>(preserveContent: true);
        var usage = body["usage"] as Newtonsoft.Json.Linq.JObject;
        if (usage == null) { return 0; }
        var total = usage["total_tokens"];
        if (total == null) { return 0; }
        return total.Value<int>();
    } catch {
        return 0;
    }
}

@{
            var currentRaw = (string)context.Variables.GetValueOrDefault("ptu-consumed-current-raw", "0");
            int current = 0;
            int.TryParse(currentRaw, out current);

            var estimated = (int)context.Variables["estimated-tokens"];
            var actual = (int)context.Variables["actual-tokens"];

            // Release the over-estimate: subtract (estimated - actual)
            // But also account for actual consumption (the estimate was pre-added)
            // Net effect: counter should reflect actual consumption, not estimate
            var adjustment = estimated - actual;
            var adjusted = current - adjustment;

            // Don't go negative
            return adjusted > 0 ? adjusted : 0;
        }

@{
            var raw = (string)context.Variables.GetValueOrDefault("std-consumed-raw", "0");
            int current = 0;
            int.TryParse(raw, out current);
            return current + (int)context.Variables["actual-tokens"];
        }
